update exampaper_question_db db
set db.answerid=#{ANSWERID,jdbcType=VARCHAR}
where db.eid = #{EID,jdbcType=VARCHAR} and db.qid=#{QID,jdbcType=VARCHAR}

update question_db db
set db.answerid=#{ANSWERID,jdbcType=VARCHAR}
where db.id=#{QID,jdbcType=VARCHAR}

update exampaper_question_db db
set db.qorder = ''||#{qorder}||'', db.th = ''||#{th}||''
where db.eid = #{eid,jdbcType=VARCHAR} and db.qid=#{qid,jdbcType=VARCHAR}

update exampaper_questiontype db
set db.qtorder = #{qtorder}
where db.eid = #{eid,jdbcType=VARCHAR} and db.qtid=#{qtid,jdbcType=VARCHAR}

update exampaper_question_db epq
set (epq.score) = #{qtscore}
where epq.eid = #{ei_id,jdbcType=VARCHAR}
and epq.qtid = #{qtid,jdbcType=VARCHAR}

  update exampaper_question_db epq
set (epq.answertime_bachelor) = #{qttime}
where epq.eid = #{ei_id,jdbcType=VARCHAR}
  and epq.qtid = #{qtid,jdbcType=VARCHAR}

update exampaper_questiontype epqt
   set epqt.questioncount = 
   (select count(epq.qid)
    from exampaper_question_db epq
    where epq.ismain = 0 and epq.eid = #{ei_id} 
    and epqt.qtid = epq.qtid
    )
 where epqt.eid = #{ei_id,jdbcType=VARCHAR}

